async function seed() {
  console.log('🌱 Starting seed...');

  // 1. Seed categories
  console.log('📁 Seeding categories...');
  for (const cat of categories) {
    const { error } = await supabase
      .from('categories')
      .upsert(cat, { onConflict: 'id' });
    if (error) {
      console.error(`❌ Category ${cat.name_ar}: ${error.message}`);
    } else {
      console.log(`✅ Category: ${cat.name_ar}`);
    }
  }

  // 2. Seed products
  console.log('📦 Seeding products...');
  let successCount = 0;
  let errorCount = 0;

  for (const prod of products) {
    const { error } = await supabase
      .from('products')
      .upsert({
        id: prod.id,
        name_ar: prod.name_ar,
        name_en: prod.name_en,
        category_id: prod.category_id,
        unit: prod.unit,
        weight: prod.weight,
        description_ar: prod.description_ar,
        description_en: prod.description_en || prod.description_ar,
        unit_price: prod.price,
        sale_price: prod.price,
        current_stock: 100,
        min_stock: 10,
        barcode: prod.id,
        is_active: true,
      }, { onConflict: 'id' });

    if (error) {
      console.error(`❌ Product ${prod.name_ar}: ${error.message}`);
      errorCount++;
    } else {
      successCount++;
    }
  }

  console.log(`\n🎉 Seed complete!`);
  console.log(`✅ Products: ${successCount}`);
  console.log(`❌ Errors: ${errorCount}`);
}

seed().catch(console.error);
